(function() {
    'use strict';

    // Function to generate random email
    function generateRandomEmail() {
        var prefix = "randomUser";
        var suffix = "@gmail.com";
        var randomNumber = Math.floor(Math.random() * 1000000);
        return prefix + randomNumber + suffix;
    }

    // Function to wait for an element to become available
    function waitForElement(selector, callback) {
        var observer = new MutationObserver(function(mutations) {
            if (document.querySelector(selector)) {
                observer.disconnect();
                callback();
            }
        });

        observer.observe(document.body, {
            childList: true,
            subtree: true
        });
    }

    // Function to set the value of an input element and dispatch events
    function setInputValue(inputId, value) {
        var inputElement = document.querySelector(`#${inputId}`);
        if (inputElement) {
            inputElement.value = value;
            inputElement.dispatchEvent(new Event('input', { bubbles: true }));
            inputElement.dispatchEvent(new Event('change', { bubbles: true }));
        } else {
            console.error(`Element with ID ${inputId} not found.`);
        }
    }

    // Function to click the submit button
    function clickSubmitButton() {
        var submitButton = document.querySelector('button[type="submit"]');
        if (submitButton) {
            submitButton.click();
            setTimeout(function() {
                location.reload();
            }, 500);
        } else {
            console.error('Submit button not found.');
        }
    }

    // Start the process of setting the input and submitting the form
    function startFillingProcess() {
        setInputValue('mat-input-2', generateRandomEmail());
        setInputValue('mat-input-3', "Aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa1");

        // Wait a bit before clicking the submit button to ensure all input events have processed
        setTimeout(clickSubmitButton, 500);
